SELECT 
FROM tpl_template
WHERE is_deleted = 0

    AND template_name LIKE CONCAT('%', #{templateName}, '%')


    AND template_type = #{templateType}


    AND industry_code = #{industryCode}


    AND audit_year = #{auditYear}


    AND status = #{status}

ORDER BY create_time DESC

SELECT 
FROM tpl_template
WHERE industry_code = #{industryCode}
  AND audit_year = #{auditYear}
  AND is_deleted = 0 AND status = 1
ORDER BY template_type, template_code
